+const WRITE_ZERO_MAX_RETRIES: usize = 10;
+
+/// Initial backoff duration when a write returns `Ok(0)`.
+const WRITE_ZERO_BACKOFF: std::time::Duration = std::time::Duration::from_millis(10);
